import { useState } from 'react';
import styled from 'styled-components';
import { Play, CheckCircle, XCircle, Copy, Check } from '@mui/icons-material';
import axios from 'axios';

const CodeContainer = styled.div`
  background-color: #1e1e1e;
  border-radius: 8px;
  overflow: hidden;
  margin: 12px 0;
`;

const CodeHeader = styled.div`
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 8px 12px;
  background-color: #2d2d2d;
`;

const LanguageBadge = styled.span`
  font-size: 12px;
  color: #4ec9b0;
  font-weight: 600;
`;

const CodeActions = styled.div`
  display: flex;
  gap: 8px;
`;

const ActionButton = styled.button`
  background: none;
  border: none;
  color: #888888;
  cursor: pointer;
  padding: 4px;
  border-radius: 4px;
  transition: color 0.2s;

  &:hover {
    color: #ffffff;
  }
`;

const CodeContent = styled.pre`
  padding: 12px;
  margin: 0;
  font-family: 'Monaco', 'Consolas', monospace;
  font-size: 13px;
  line-height: 1.5;
  overflow-x: auto;
  color: #d4d4d4;
  white-space: pre-wrap;
  word-break: break-all;
`;

const ExecutionResult = styled.div`
  padding: 12px;
  border-top: 1px solid #3d3d3d;
`;

const ResultHeader = styled.div`
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 8px;
`;

const ResultStatus = styled.span`
  display: flex;
  align-items: center;
  gap: 4px;
  font-size: 12px;
  font-weight: 600;

  &.success {
    color: #4ec9b0;
  }

  &.error {
    color: #f14c4c;
  }
`;

const ResultOutput = styled.pre`
  background-color: #0d1117;
  padding: 12px;
  border-radius: 6px;
  font-family: 'Monaco', 'Consolas', monospace;
  font-size: 13px;
  line-height: 1.5;
  overflow-x: auto;
  margin: 0;

  &.success {
    color: #a5d6a7;
  }

  &.error {
    color: #ffcdd2;
  }
`;

function CodeBlock({ code }) {
  const [output, setOutput] = useState(null);
  const [isRunning, setIsRunning] = useState(false);
  const [copied, setCopied] = useState(false);

  const handleExecute = async () => {
    setIsRunning(true);
    try {
      const response = await axios.post('http://localhost:5000/api/python/execute', {
        code: code
      });
      setOutput(response.data);
    } catch (error) {
      setOutput({ success: false, error: error.message });
    } finally {
      setIsRunning(false);
    }
  };

  const handleCopy = async () => {
    await navigator.clipboard.writeText(code);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <CodeContainer>
      <CodeHeader>
        <LanguageBadge>Python</LanguageBadge>
        <CodeActions>
          <ActionButton onClick={handleCopy} title="复制代码">
            {copied ? <Check style={{ fontSize: '16px' }} /> : <Copy style={{ fontSize: '16px' }} />}
          </ActionButton>
          <ActionButton onClick={handleExecute} disabled={isRunning} title="执行代码">
            {isRunning ? (
              <div style={{ width: '16px', height: '16px', border: '2px solid #888', borderTopColor: 'transparent', borderRadius: '50%', animation: 'spin 1s linear infinite' }} />
            ) : (
              <Play style={{ fontSize: '16px' }} />
            )}
          </ActionButton>
        </CodeActions>
      </CodeHeader>
      <CodeContent>{code}</CodeContent>
      {output && (
        <ExecutionResult>
          <ResultHeader>
            <ResultStatus className={output.success ? 'success' : 'error'}>
              {output.success ? <CheckCircle /> : <XCircle />}
              {output.success ? '执行成功' : '执行失败'}
            </ResultStatus>
          </ResultHeader>
          {(output.output || output.error) && (
            <ResultOutput className={output.success ? 'success' : 'error'}>
              {output.error || output.output}
            </ResultOutput>
          )}
        </ExecutionResult>
      )}
      <style>{`
        @keyframes spin {
          to { transform: rotate(360deg); }
        }
      `}</style>
    </CodeContainer>
  );
}

export default CodeBlock;
